  width: 100%;
}

.canvas-matter {
  width: 100%;
  margin-bottom: 0;
  position: absolute;
  bottom: 0%;
  left: 0%;
  overflow: hidden;
  pointer-events: none;
}

.canvas-matter__before {
  padding-top: 100%;
}

.canvas-matter__target {
  transform: scale3d(1none, 1none, 1none);
  transform-style: preserve-3d;
  width: 100%;
  height: 100%;
  position: absolute;
  top: 0;
  left: 0;
  overflow: hidden;
}

#canvas-target canvas {
  position: relative;
  top: -1px;
  left: -1px;
  right: -1px;
  bottom: -1px;
  max-width: unset;
  pointer-events: all;
  max-width: calc(100% + 2px);
  max-height: calc(100% + 2px);
  min-width: calc(100% + 2px);
  min-height: calc(100% + 2px);
}

Step 2: Add custom Javascript

function initFalling2DMatterJS() {

  const canvas = document.querySelector("#canvas-target");

  // Check if canvas is on page
  if (!canvas) {
    return;
  }

  const canvasWidth = canvas.clientWidth + 2;
  const canvasHeight = canvas.clientHeight + 2;
  const canvasWallDepth = canvasWidth / 4;
  const smileyAmount = 15; // Amount of objects added to the canvas
  const smileySize = canvasWidth / 7.5; // Size of objects
  const smileySizeTexture = 256; // Size of object texture in pixels
  const smileySizeScale = smileySize / smileySizeTexture;
  const smileyRestitution = 0.75; // Bounciness
  const worldGravity = 2; // Gravity

  // Modules
  let { Engine, Render, Runner, Bodies, Composite, Mouse, MouseConstraint } = Matter;

  // Create an engine
  let engine = Engine.create();
  engine.world.gravity.y = worldGravity;

  // Create a renderer
  let render = Render.create({
    element: canvas,
    engine: engine,
    options: {
      background: "transparent",
      wireframes: false,
      width: canvasWidth,
      height: canvasHeight,
      pixelRatio: 2,
      border: "none",
    }
  });

  // Generate a random number between min (inclusive) and max (exclusive)
  function getRandomNumber(min, max) {
    return Math.random() * (max - min) + min;
  }

  let min = smileySize / 2; // min value
  let max = canvasWidth - (smileySize / 2); // max value

  // Textures
  let textureArray = [
    'https://cdn.prod.website-files.com/67f388c94c43e20cfb7ca732/67f394c931c1e6fc303e12ec_smiley-1.svg',
    'https://cdn.prod.website-files.com/67f388c94c43e20cfb7ca732/67f394c9718ec3640accf3d4_smiley-2.svg',
    'https://cdn.prod.website-files.com/67f388c94c43e20cfb7ca732/67f394c940dfb6d33af4c6d6_smiley-3.svg',
    'https://cdn.prod.website-files.com/67f388c94c43e20cfb7ca732/67f394c9ab4fc0301d56d8c5_smiley-4.svg',
    'https://cdn.prod.website-files.com/67f388c94c43e20cfb7ca732/67f394c9d9ee6112fdb67b89_smiley-5.svg'
  ];

  // Function to loop trough all textures
  let textureIndex = 0;
  function getNextTexture() {
    const texture = textureArray[textureIndex];
    textureIndex = (textureIndex + 1) % textureArray.length;
    return texture;
  }

  // Function to get a random texture
  function getRandomTexture() {
    const randomIndex = Math.floor(Math.random() * textureArray.length);
    return textureArray[randomIndex];
  }

  // Create smiley
  const smileyCreate = () => {
    let smiley = Bodies.rectangle(getRandomNumber(min, max), smileySize, smileySize,
      smileySize, {
        chamfer: { 
          radius: smileySize / 2
        },
        restitution: smileyRestitution,
        render: {
          sprite: {
            texture: getNextTexture(), // Replace with "getRandomTexture()" to get random textures
            xScale: smileySizeScale,
            yScale: smileySizeScale
          }
        }
      });
    Composite.add(engine.world, smiley);
  };

  // Create a box with rectangle(x, y, width, height)
  let boxTop = Bodies.rectangle(canvasWidth / 2 + (canvasWallDepth * 2), canvasHeight +
    canvasWallDepth, canvasWidth + (canvasWallDepth * 4), (canvasWallDepth * 2), {
      isStatic: true
    });

  let boxLeft = Bodies.rectangle((canvasWallDepth * -1), canvasHeight / 2, (canvasWallDepth * 2),
    canvasHeight, {
      isStatic: true
    });

  let boxRight = Bodies.rectangle(canvasWidth + canvasWallDepth, canvasHeight / 2, (
    canvasWallDepth * 2), canvasHeight, {
    isStatic: true
  });

  let boxBottom = Bodies.rectangle(canvasWidth / 2 + (canvasWallDepth * 2), (canvasWallDepth * -1),
    canvasWidth + (canvasWallDepth * 4), (canvasWallDepth * 2), {
      isStatic: true
    });

  // Add all of the bodies to the world
  Composite.add(engine.world, [boxTop, boxLeft, boxRight, boxBottom]);

  // Run the renderer
  Render.run(render);

  // Create runner
  let runner = Runner.create();

  // Run the engine
  Matter.Runner.run(runner, engine);

  // Custom Function: 
  // To run the function X amount of times
  function repeatedFunction(count, maxCount) {
    if (count < maxCount) {
      smileyCreate();
      setTimeout(() => {
        repeatedFunction(count + 1, maxCount);
      }, 100); // Delay in milliseconds
    }
  }
  repeatedFunction(0, smileyAmount);

  // Create mouse
  let mouse = Mouse.create(render.canvas);
  let mouseConstraint = MouseConstraint.create(engine, {
    mouse: mouse,
    constraint: {
      stiffness: 0.2,
      render: {
        visible: false
      }
    }
  });

  Composite.add(engine.world, mouseConstraint);

  // Fix: Allow native page scroll
  mouseConstraint.mouse.element.removeEventListener("mousewheel", mouseConstraint.mouse.mousewheel);
  mouseConstraint.mouse.element.removeEventListener("DOMMouseScroll", mouseConstraint.mouse.mousewheel);

  // Fix: Scroll on touch devices
  mouseConstraint.mouse.element.removeEventListener('touchstart', mouseConstraint.mouse.mousedown);
  mouseConstraint.mouse.element.removeEventListener('touchmove', mouseConstraint.mouse.mousemove);
  mouseConstraint.mouse.element.removeEventListener('touchend', mouseConstraint.mouse.mouseup);

  mouseConstraint.mouse.element.addEventListener('touchstart', mouseConstraint.mouse.mousedown, { passive: true });
  mouseConstraint.mouse.element.addEventListener('touchmove', (e) => {
    if (mouseConstraint.body) {
      mouseConstraint.mouse.mousemove(e);
    }
  });
  mouseConstraint.mouse.element.addEventListener('touchend', (e) => {
    if (mouseConstraint.body) {
      mouseConstraint.mouse.mouseup(e);
    }
  });
}

// Initialize Falling 2D Elements (Matter.js)
document.addEventListener('DOMContentLoaded', function() {
  initFalling2DMatterJS();
});

Implementation

Canvas
The script looks for #canvas-target and injects a  into it, so make sure that element exists on your page. We also use a .canvas-matter__before element to maintain a consistent 1:1 aspect ratio for the canvas.

Textures
We used a set of 5 different smileys, but you can replace them with any visuals you like. This resource is designed for images with a 1:1 aspect ratio.
You have the ability to choose between a random texture or select the next in line. Use one of the two below:

- Random texture: getRandomTexture()
- Loop trough array: getNextTexture()

Customization options
- smileyAmount Amount of objects added to the canvas
- smileySize Size of objects
- smileySizeTexture Size of object texture in pixels
- smileyRestitution Set Bounciness of the falling objects
- worldGravity Set world gravity
Changing the size, aspect ratio, or roundness of the objects is more advanced. To keep this resource simple, we recommend checking the official Matter.js Documentation for all available options.
